// Helpers
const get = <T,>(key: string, defaultVal: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultVal;
};

const set = <T,>(key: string, data: T) => {
  localStorage.setItem(key, JSON.stringify(data));
};

