const guessGender = (name: string): Gender => {
  const lower = name.toLowerCase();
  const femaleKeywords = [
    'putri', 'nur', 'siti', 'zahra', 'aira', 'syifa', 'ina', 'ayu', 'nisa', 
    'aulia', 'annisa', 'suci', 'dwi', 'fika', 'gadis', 'nadia', 'nasywa', 
