import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
    // Note: In a real app, API key should come from env. 
    // Here we assume process.env.API_KEY is available as per instructions.
    if (!process.env.API_KEY) {
        throw new Error("API Key missing");
    }
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

export const editImageWithGemini = async (base64Image: string, prompt: string, mimeType: string): Promise<string> => {
    const ai = getAIClient();
    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image',
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Image
                        }
                    },
                    {
                        text: prompt
                    }
                ]
            }
        });

        // Parse response for image
        if (response.candidates && response.candidates[0].content && response.candidates[0].content.parts) {
            for (const part of response.candidates[0].content.parts) {
                if (part.inlineData && part.inlineData.data) {
                    return `data:${part.inlineData.mimeType || 'image/png'};base64,${part.inlineData.data}`;
                }
            }
        }
        throw new Error("No image generated");
    } catch (error) {
        console.error("Gemini Image Edit Error", error);
        throw error;
    }
};

export interface SearchResult {
    text: string;
    links: { title: string; uri: string }[];
}

export const searchTeachingResources = async (query: string): Promise<SearchResult> => {
    const ai = getAIClient();
    try {
        const response: GenerateContentResponse = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: `Search for this topic related to Arabic teaching: ${query}. Provide a summary and list relevant resources.`,
            config: {
                tools: [{ googleSearch: {} }],
            },
        });

        const text = response.text || "No results found.";

        const links: { title: string; uri: string }[] = [];
        const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

        if (chunks) {
            chunks.forEach((chunk: any) => {
                if (chunk.web) {
                    links.push({ title: chunk.web.title, uri: chunk.web.uri });
                }
            });
        }

        return { text, links };
    } catch (error) {
        console.error("Gemini Search Error", error);
        throw error;
    }
};

export const generateReportComment = async (studentName: string, avgFormatif: number, avgSumatif: number, nilaiSas: number, finalScore: number): Promise<string> => {
    const ai = getAIClient();
    try {
        const prompt = `
            Anda adalah Wali Kelas di MTsN 2 Bulukumba. Buatkan catatan rapor singkat (maksimal 2 kalimat) dalam Bahasa Indonesia untuk siswa bernama "${studentName}".

            Data Nilai (Bahasa Arab):
            - Rata-rata Formatif (Tugas/Harian): ${avgFormatif.toFixed(0)}
            - Rata-rata Sumatif (Ulangan): ${avgSumatif.toFixed(0)}
            - Sumatif Akhir Semester (Ujian): ${nilaiSas.toFixed(0)}
            - Nilai Akhir: ${finalScore.toFixed(0)}
            - KKM (Batas Tuntas): 72

            Aturan:
            1. Jika Nilai Akhir >= 90: Puji pencapaian luar biasa dan pertahankan.
            2. Jika Nilai Akhir >= 72 dan < 90: Apresiasi usaha, namun berikan saran spesifik (misal: tingkatkan hafalan kosa kata jika formatif rendah, atau teliti saat ujian jika SAS rendah).
            3. Jika Nilai Akhir < 72: Gunakan bahasa yang memotivasi (jangan memarahi), sarankan belajar lebih giat dan bertanya pada guru.
            4. Gunakan nada bicara yang bijak, islami, dan menyemangati.
        `;

        const response: GenerateContentResponse = await ai.models.generateContent({
            model: "gemini-3-flash-preview",
            contents: prompt,
        });

        return response.text || "Teruslah belajar dengan giat.";
    } catch (error) {
        console.error("Gemini Comment Gen Error", error);
        return "Teruslah belajar dan berdoa untuk kesuksesanmu.";
    }
};

import React, { useEffect, useState } from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
} from 'chart.js';
import { Bar, Pie } from 'react-chartjs-2';
import { getClasses, getStudents, getGrades } from '../services/storageService';
import { KKM, WEIGHTS } from '../constants';

// Register ChartJS components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement
);

export const Dashboard: React.FC = () => {
  const [stats, setStats] = useState({
    totalClasses: 0,
    totalStudents: 0,
    passRate: 0,
    averageScore: 0,
    highestScore: 0,
    lowestScore: 0
  });

  const [barData, setBarData] = useState<any>(null);
  const [pieData, setPieData] = useState<any>(null);
  const [distData, setDistData] = useState<any>(null);

  useEffect(() => {
    const classes = getClasses();
    const students = getStudents();
    const grades = getGrades();

    let totalScore = 0;
    let passedCount = 0;
    let failedCount = 0;
    let gradedCount = 0;
    let maxScore = 0;
    let minScore = 100;

    const classLabels: string[] = [];
    const classAvgScores: number[] = [];

    // Distribution Buckets
    let distA = 0; // 90-100
    let distB = 0; // 80-89
    let distC = 0; // 72-79
    let distD = 0; // < 72

    classes.forEach(cls => {
      classLabels.push(cls.name);
      const clsStudents = students.filter(s => s.classId === cls.id);
      let clsTotal = 0;
      let clsGraded = 0;

      clsStudents.forEach(student => {
        const grade = grades.find(g => g.studentId === student.id);
        if (grade) {
          const avgF = grade.formatif.reduce((a, b) => a + b, 0) / (grade.formatif.filter(n => n > 0).length || 1);
          const avgS = grade.sumatif.reduce((a, b) => a + b, 0) / (grade.sumatif.filter(n => n > 0).length || 1);
          const sas = (grade.sasNonTes + grade.sasTes) / 2;
          const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);

          if (final > 0) {
            totalScore += final;
            clsTotal += final;
            gradedCount++;
            clsGraded++;

            if (final > maxScore) maxScore = final;
            if (final < minScore) minScore = final;

            if (final >= KKM) {
              passedCount++;
            } else {
              failedCount++;
            }

            // Distribution
            if (final >= 90) distA++;
            else if (final >= 80) distB++;
            else if (final >= KKM) distC++;
            else distD++;
          }
        }
      });

      classAvgScores.push(clsGraded > 0 ? parseFloat((clsTotal / clsGraded).toFixed(1)) : 0);
    });

    setStats({
      totalClasses: classes.length,
      totalStudents: students.length,
      passRate: gradedCount > 0 ? Math.round((passedCount / gradedCount) * 100) : 0,
      averageScore: gradedCount > 0 ? Math.round(totalScore / gradedCount) : 0,
      highestScore: gradedCount > 0 ? Math.round(maxScore) : 0,
      lowestScore: gradedCount > 0 && minScore !== 100 ? Math.round(minScore) : 0
    });

    // Bar Chart: Rata-rata Kelas
    setBarData({
      labels: classLabels,
      datasets: [
        {
          label: 'Rata-rata Nilai',
          data: classAvgScores,
          backgroundColor: 'rgba(25, 135, 84, 0.7)',
          borderColor: 'rgba(25, 135, 84, 1)',
          borderWidth: 1,
          borderRadius: 4,
        },
      ],
    });

    // Pie Chart: Ketuntasan
    setPieData({
      labels: ['Tuntas (>= KKM)', 'Remedial (< KKM)'],
      datasets: [
        {
          data: [passedCount, failedCount],
          backgroundColor: [
            'rgba(25, 135, 84, 0.8)', // Islamic Green
            'rgba(220, 53, 69, 0.8)', // Red
          ],
          borderColor: ['#fff', '#fff'],
          borderWidth: 2,
        },
      ],
    });

    // Bar Chart: Distribusi Predikat
    setDistData({
      labels: ['A (90-100)', 'B (80-89)', 'C (72-79)', 'D (< 72)'],
      datasets: [
        {
          label: 'Jumlah Siswa',
          data: [distA, distB, distC, distD],
          backgroundColor: [
            'rgba(25, 135, 84, 0.9)', // A
            'rgba(13, 110, 253, 0.8)', // B
            'rgba(255, 193, 7, 0.8)', // C
            'rgba(220, 53, 69, 0.8)', // D
          ],
          borderWidth: 0,
          borderRadius: 4
        }
      ]
    });

  }, []);

  return (
    <div className="container-fluid p-0">
      <div className="d-flex justify-content-between align-items-center mb-4 border-bottom pb-2">
         <h2 className="text-dark font-arabic mb-0">Dashboard Statistik</h2>
         <span className="text-muted small">Tahun Pelajaran 2024/2025</span>
      </div>

      {/* Info Cards Row 1 */}
      <div className="row g-3 mb-3">
        <div className="col-md-3">
          <div className="card h-100 border-0 shadow-sm" style={{borderLeft: '4px solid #0f5132'}}>
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center">
                  <div>
                    <h6 className="card-title text-muted text-uppercase small mb-1">Total Kelas</h6>
                    <h2 className="mb-0 fw-bold text-dark">{stats.totalClasses}</h2>
                  </div>
                  <div className="bg-success bg-opacity-10 text-success p-3 rounded-circle">
                    🏫
                  </div>
              </div>
            </div>
          </div>
        </div>
        <div className="col-md-3">
          <div className="card h-100 border-0 shadow-sm" style={{borderLeft: '4px solid #198754'}}>
            <div className="card-body">
              <div className="d-flex justify-content-between align-items-center">
                  <div>
                    <h6 className="card-title text-muted text-uppercase small mb-1">Total Siswa</h6>
                    <h2 className="mb-0 fw-bold text-dark">{stats.totalStudents}</h2>
