import React, { useState, useEffect, useMemo } from 'react';
import { Student, GradeData, Classroom } from '../types';
import { getClasses, getStudentsByClass, getGradeByStudent, saveGrade, getUserProfile } from '../services/storageService';
import { KKM, WEIGHTS, SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';
import { generateReportComment } from '../services/geminiService';

export const GradingSheet: React.FC = () => {
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [grades, setGrades] = useState<Record<string, GradeData>>({});

  // Save status indicator
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  // AI Loading State per Student
  const [generatingFor, setGeneratingFor] = useState<string | null>(null);

  useEffect(() => {
    setClasses(getClasses());
  }, []);

  useEffect(() => {
    if (selectedClass) {
      const clsStudents = getStudentsByClass(selectedClass);
      setStudents(clsStudents);
      const gradeMap: Record<string, GradeData> = {};
      clsStudents.forEach(s => {
        gradeMap[s.id] = getGradeByStudent(s.id);
      });
      setGrades(gradeMap);
    }
  }, [selectedClass]);

  const triggerAutoSave = (updatedGrade: GradeData) => {
      setSaveStatus('saving');
      saveGrade(updatedGrade);
      setTimeout(() => {
          setSaveStatus('saved');
          setTimeout(() => setSaveStatus('idle'), 2000);
      }, 600);
  };

  const handleGradeChange = (studentId: string, field: 'formatif' | 'sumatif', index: number, value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId] };
    if (field === 'formatif') {
      const newF = [...currentGrade.formatif];
      newF[index] = numVal;
      currentGrade.formatif = newF;
    } else {
      const newS = [...currentGrade.sumatif];
      newS[index] = numVal;
      currentGrade.sumatif = newS;
    }
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    triggerAutoSave(currentGrade);
  };

  const handleSasChange = (studentId: string, field: 'sasNonTes' | 'sasTes', value: string) => {
    const numVal = parseFloat(value) || 0;
    const currentGrade = { ...grades[studentId], [field]: numVal };
    setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
    triggerAutoSave(currentGrade);
  };

  const handleNoteChange = (studentId: string, value: string) => {
      const currentGrade = { ...grades[studentId], teacherNote: value };
      setGrades(prev => ({ ...prev, [studentId]: currentGrade }));
      triggerAutoSave(currentGrade);
  };

  const handleGenerateAIComment = async (student: Student, calculatedData: any) => {
      setGeneratingFor(student.id);
      try {
          const comment = await generateReportComment(
              student.name, 
              calculatedData.avgF, 
              calculatedData.avgS, 
              calculatedData.sas, 
              calculatedData.final
          );
          handleNoteChange(student.id, comment);
      } catch (e) {
          alert('Gagal generate komentar AI. Periksa koneksi atau API Key.');
      } finally {
          setGeneratingFor(null);
      }
  };

  const getLetterGrade = (score: number) => {
      if (score >= 90) return { letter: 'A', color: 'bg-success' };
      if (score >= 80) return { letter: 'B', color: 'bg-primary' };
      if (score >= 70) return { letter: 'C', color: 'bg-info text-dark' };
      if (score >= 60) return { letter: 'D', color: 'bg-warning text-dark' };
      return { letter: 'E', color: 'bg-danger' };
  };

  // Automated Calculations & Ranking
  const calculatedData = useMemo(() => {
    const processed = students.map(s => {
      const g = grades[s.id];
      if (!g) return null;

      const validF = g.formatif.filter(n => n > 0);
      const avgF = validF.length > 0 ? validF.reduce((a, b) => a + b, 0) / validF.length : 0;

      const validS = g.sumatif.filter(n => n > 0);
      const avgS = validS.length > 0 ? validS.reduce((a, b) => a + b, 0) / validS.length : 0;

      const sas = (g.sasNonTes + g.sasTes) / 2;

      const final = (avgF * WEIGHTS.FORMATIF) + (avgS * WEIGHTS.SUMATIF) + (sas * WEIGHTS.SAS);
      const isPassing = final >= KKM;
      const letter = getLetterGrade(final);

      return {
        ...s,
        g,
        avgF,
        avgS,
        sas,
        final,
        isPassing,
        letter
      };
    });

    const validProcessed = processed.filter(p => p !== null) as NonNullable<typeof processed[0]>[];
    const sortedByScore = [...validProcessed].sort((a, b) => b.final - a.final);
    const rankMap: Record<string, number> = {};
    sortedByScore.forEach((item, index) => {
        rankMap[item.id] = index + 1;
    });

    return validProcessed.map(item => ({
        ...item,
        rank: rankMap[item.id]
    }));

  }, [students, grades]);

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Input & Rekap Nilai</h2>
        <div className="d-flex gap-2">
            <select 
                className="form-select"
                value={selectedClass}
                onChange={(e) => setSelectedClass(e.target.value)}
            >
                <option value="">-- Pilih Kelas --</option>
                {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>

             {selectedClass && (
                <div className="d-flex align-items-center gap-2">
                    {saveStatus === 'saving' && <span className="text-warning small fw-bold">⏳ Menyimpan...</span>}
                    {saveStatus === 'saved' && <span className="text-success small fw-bold">✅ Tersimpan</span>}
                </div>
             )}
        </div>
      </div>

      {selectedClass && (
        <div className="card shadow-sm border-0">
          <div className="card-body p-0">
            <div className="table-responsive" style={{maxHeight: '75vh'}}>
              <table className="table table-bordered table-sm mb-0 align-middle text-center" style={{fontSize: '0.85rem'}}>
                <thead className="table-success sticky-header text-white">
                  <tr>
                    <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-2" style={{minWidth: '40px', left: 0}}>No</th>
                    <th rowSpan={2} className="align-middle sticky-col sticky-header-col p-2 text-start" style={{minWidth: '220px', left: '40px'}}>Nama Siswa</th>
                    <th colSpan={8} className="align-middle sticky-header">Formatif (Tugas/Harian)</th>
                    <th colSpan={5} className="align-middle sticky-header">Sumatif (Ulangan)</th>
                    <th colSpan={2} className="align-middle sticky-header">SAS (Ujian)</th>
                    <th rowSpan={2} className="align-middle sticky-header bg-light text-dark fw-bold">Nilai<br/>Akhir</th>
                    <th rowSpan={2} className="align-middle sticky-header bg-light text-dark fw-bold">Pred</th>
                    <th rowSpan={2} className="align-middle sticky-header bg-light text-dark fw-bold">Ket</th>
                    <th rowSpan={2} className="align-middle sticky-header text-center" style={{minWidth: '250px'}}>Catatan Wali Kelas (AI)</th>
                  </tr>
                  <tr>
                     {[1,2,3,4,5,6,7,8].map(i => <th key={`f${i}`} className="sticky-header fw-normal" style={{minWidth: '40px'}}>F{i}</th>)}
                     {[1,2,3,4,5].map(i => <th key={`s${i}`} className="sticky-header fw-normal" style={{minWidth: '40px'}}>S{i}</th>)}
                     <th className="sticky-header fw-normal" style={{minWidth: '50px'}}>Non</th>
                     <th className="sticky-header fw-normal" style={{minWidth: '50px'}}>Tes</th>
                  </tr>
                </thead>
                <tbody>
                  {calculatedData.map((row, idx) => (
                    <tr key={row.id}>
                      <td className="sticky-col bg-white" style={{left: 0}}>{idx + 1}</td>
                      <td className="sticky-col bg-white text-start fw-bold" style={{left: '40px'}}>{row.name}</td>

                      {/* Formatif Inputs */}
                      {row.g.formatif.map((val, i) => (
                        <td key={`f-${i}`} className="p-0">
                          <input type="number" className="form-control form-control-sm border-0 text-center p-1" 
                                 value={val || ''} min={0} max={100}
                                 onChange={e => handleGradeChange(row.id, 'formatif', i, e.target.value)} />
                        </td>
                      ))}

                      {/* Sumatif Inputs */}
                      {row.g.sumatif.map((val, i) => (
                        <td key={`s-${i}`} className="p-0">
                          <input type="number" className="form-control form-control-sm border-0 text-center p-1" 
                                 value={val || ''} min={0} max={100}
                                 onChange={e => handleGradeChange(row.id, 'sumatif', i, e.target.value)} />
                        </td>
                      ))}

                      {/* SAS Inputs */}
                      <td className="p-0"><input type="number" className="form-control form-control-sm border-0 text-center p-1" value={row.g.sasNonTes || ''} onChange={e => handleSasChange(row.id, 'sasNonTes', e.target.value)} /></td>
                      <td className="p-0"><input type="number" className="form-control form-control-sm border-0 text-center p-1" value={row.g.sasTes || ''} onChange={e => handleSasChange(row.id, 'sasTes', e.target.value)} /></td>

                      {/* Results */}
                      <td className="fw-bold bg-light" style={{fontSize: '0.95rem'}}>{row.final.toFixed(0)}</td>
                      <td className={`text-white fw-bold ${row.letter.color}`}>{row.letter.letter}</td>
                      <td>
                          {row.isPassing ? <span className="text-success fw-bold">Tuntas</span> : <span className="text-danger fw-bold">Remidi</span>}
                      </td>

                      {/* Catatan & AI Button */}
                      <td className="text-start p-1 position-relative">
                          <div className="input-group input-group-sm">
                              <textarea 
                                className="form-control border-0 bg-light" 
                                rows={2} 
                                style={{fontSize: '0.8rem', resize: 'none'}}
                                placeholder="Belum ada catatan..."
                                value={row.g.teacherNote || ''}
                                onChange={e => handleNoteChange(row.id, e.target.value)}
                              ></textarea>
                              <button 
                                className="btn btn-outline-success" 
                                type="button"
                                title="Buat catatan otomatis dengan AI"
                                onClick={() => handleGenerateAIComment(row, row)}
                                disabled={generatingFor === row.id}
                              >
                                {generatingFor === row.id ? '⏳' : '✨ AI'}
                              </button>
                          </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="card-footer bg-light small text-muted">
                <strong>Rumus Nilai:</strong> ({WEIGHTS.FORMATIF*100}% Rata-rata F) + ({WEIGHTS.SUMATIF*100}% Rata-rata S) + ({WEIGHTS.SAS*100}% Rata-rata SAS). KKM: {KKM}.
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

