                     {[1,2,3,4,5].map(i => <th key={`s${i}`} className="sticky-header bg-sub-sumatif" style={{minWidth: '50px'}}>S{i}</th>)}
                     <th className="sticky-header bg-sub-sas" style={{minWidth: '60px'}}>Non</th>
                     <th className="sticky-header bg-sub-sas" style={{minWidth: '60px'}}>Tes</th>

                     <th className="sticky-header bg-light fw-bold text-dark border-bottom">Nilai</th>
                     <th className="sticky-header bg-light fw-bold text-dark border-bottom">Pred</th>
                     <th className="sticky-header bg-light fw-bold text-dark border-bottom">Ket</th>
                  </tr>
                </thead>
                <tbody>
                  {calculatedData.map((row, idx) => (
                    <tr key={row.id}>
                      <td className="sticky-col fw-bold text-secondary" style={{left: 0, zIndex: 10}}>{idx + 1}</td>
                      <td className="sticky-col text-start fw-bold text-dark" style={{left: '50px', zIndex: 10}}>{row.name}</td>

