import { Student, Classroom, GradeData, AttendanceData, JournalEntry, Gender, UserProfile } from '../types';
import { MOCK_CLASSES } from '../constants';

// Keys
const KEYS = {
  CLASSES: 'ar_classes',
  STUDENTS: 'ar_students',
  GRADES: 'ar_grades',
  ATTENDANCE: 'ar_attendance',
  JOURNAL: 'ar_journal',
  PROFILE: 'ar_user_profile',
  SEEDED: 'ar_seeded_v6' // Bump version to force re-seed if structure changes significantly
};

// Helpers
const get = <T,>(key: string, defaultVal: T): T => {
  const data = localStorage.getItem(key);
  return data ? JSON.parse(data) : defaultVal;
};

const set = <T,>(key: string, data: T) => {
  localStorage.setItem(key, JSON.stringify(data));
};

// --- PROFILE ---
export const getUserProfile = (): UserProfile => {
  return get<UserProfile>(KEYS.PROFILE, {
    name: 'HARMA, S.Pd.I',
    nip: '19850101 201001 1 001',
    role: 'Guru Bahasa Arab',
    photo: '' // Empty string defaults to placeholder in UI
  });
};

export const saveUserProfile = (profile: UserProfile) => {
  set(KEYS.PROFILE, profile);
};

// Helper: Simple Gender Guesser based on Name
const guessGender = (name: string): Gender => {
  const lower = name.toLowerCase();
  const femaleKeywords = [
