import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { ClassManager } from './components/ClassManager';
import { StudentManager } from './components/StudentManager';
import { GradingSheet } from './components/GradingSheet';
import { AttendanceSheet } from './components/AttendanceSheet';
import { JournalManager } from './components/JournalManager';
import { TeachingMaterials } from './components/TeachingMaterials';
import { AITools } from './components/AITools';
import { Login } from './components/Login';
import { ProfileManager } from './components/ProfileManager';
import { ViewState, UserProfile } from './types';
import { getUserProfile } from './services/storageService';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>(ViewState.LOGIN);
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [userProfile, setUserProfile] = useState<UserProfile>(getUserProfile());

  // Simulate checking session on mount
  useEffect(() => {
    const session = localStorage.getItem('ar_app_session');
    if (session === 'active') {
      setIsAuthenticated(true);
      setCurrentView(ViewState.DASHBOARD);
      // Load fresh profile
      setUserProfile(getUserProfile());
    }
  }, []);

  const handleLogin = () => {
    localStorage.setItem('ar_app_session', 'active');
    setIsAuthenticated(true);
    setCurrentView(ViewState.DASHBOARD);
    setUserProfile(getUserProfile());
  };

  const handleLogout = () => {
    localStorage.removeItem('ar_app_session');
    setIsAuthenticated(false);
    setCurrentView(ViewState.LOGIN);
  };

  const handleProfileUpdate = (updated: UserProfile) => {
      setUserProfile(updated);
  };

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const renderContent = () => {
    switch (currentView) {
      case ViewState.DASHBOARD:
        return <Dashboard />;
      case ViewState.CLASSES:
        return <ClassManager />;
      case ViewState.STUDENTS:
        return <StudentManager />;
      case ViewState.GRADING:
        return <GradingSheet />;
      case ViewState.ATTENDANCE:
        return <AttendanceSheet />;
      case ViewState.JOURNAL:
        return <JournalManager />;
      case ViewState.MATERIALS:
        return <TeachingMaterials />;
      case ViewState.AI_TOOLS:
        return <AITools />;
      case ViewState.PROFILE:
        return <ProfileManager userProfile={userProfile} onProfileUpdate={handleProfileUpdate} />;
      default:
        return <Dashboard />;
    }
  };

  return (
    <Layout 
        currentView={currentView} 
        onViewChange={setCurrentView} 
        onLogout={handleLogout}
        userProfile={userProfile}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { TeachingMaterial } from '../types';
import { getMaterials, saveMaterial, deleteMaterial } from '../services/storageService';

export const TeachingMaterials: React.FC = () => {
  const [materials, setMaterials] = useState<TeachingMaterial[]>([]);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(false);

  // Form State
  const [title, setTitle] = useState('');
  const [category, setCategory] = useState<'RPP/Modul' | 'Silabus/ATP' | 'Media' | 'Lainnya'>('RPP/Modul');
  const [type, setType] = useState<'PDF' | 'DOC' | 'LINK'>('PDF');
  const [fileInput, setFileInput] = useState<File | null>(null);
  const [linkInput, setLinkInput] = useState('');

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    const data = getMaterials();
    // Sort by date (newest first)
    setMaterials(data.sort((a, b) => new Date(b.uploadDate).getTime() - new Date(a.uploadDate).getTime()));
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFileInput(e.target.files[0]);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    let fileData = '';
    let fileSize = '';
    let fileName = '';

    if (type === 'LINK') {
      fileData = linkInput;
      fileSize = 'External';
      fileName = 'Link Web/Drive';
    } else if (fileInput) {
      // Limit file size for LocalStorage (e.g., 500KB)
      if (fileInput.size > 500 * 1024) {
        alert('Maaf, untuk penyimpanan lokal browser, ukuran file dibatasi maksimal 500KB. Gunakan opsi "Link Eksternal" (Google Drive) untuk file besar.');
        setLoading(false);
        return;
      }

      fileName = fileInput.name;
      fileSize = (fileInput.size / 1024).toFixed(1) + ' KB';

      // Convert to Base64
      fileData = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(fileInput);
      });
    }

    const newMaterial: TeachingMaterial = {
      id: Date.now().toString(),
      title,
      category,
      type,
      uploadDate: new Date().toISOString().split('T')[0],
      fileData,
      fileName,
      fileSize
    };

    saveMaterial(newMaterial);
    refreshData();
    resetForm();
    setLoading(false);
    setShowForm(false);
  };

  const resetForm = () => {
    setTitle('');
    setCategory('RPP/Modul');
    setType('PDF');
    setFileInput(null);
    setLinkInput('');
  };

  const handleDelete = (id: string) => {
    if(confirm('Hapus perangkat ajar ini?')) {
        deleteMaterial(id);
        refreshData();
    }
  };

  const getIcon = (type: string) => {
    switch(type) {
        case 'PDF': return '📕';
        case 'DOC': return '📘';
        case 'LINK': return '🔗';
        default: return '📄';
    }
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
            <h2 className="text-dark fw-bold">Perangkat Pembelajaran</h2>
            <p className="text-muted mb-0">Arsip RPP, Modul Ajar, ATP, dan Media Pembelajaran.</p>
        </div>
        <button 
            className={`btn ${showForm ? 'btn-secondary' : 'btn-success'} shadow-sm`}
            onClick={() => setShowForm(!showForm)}
        >
            {showForm ? 'Batal' : '➕ Upload Perangkat'}
        </button>
      </div>

      {showForm && (
        <div className="card shadow border-0 mb-4 border-start border-4 border-success animate__animated animate__fadeIn">
          <div className="card-body">
            <h5 className="fw-bold mb-3">Upload Dokumen Baru</h5>
            <form onSubmit={handleSubmit}>
                <div className="row g-3">
                    <div className="col-md-6">
                        <label className="form-label">Judul Perangkat</label>
                        <input type="text" className="form-control" value={title} onChange={e => setTitle(e.target.value)} required placeholder="Contoh: Modul Ajar Bab 2" />
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Kategori</label>
                        <select className="form-select" value={category} onChange={e => setCategory(e.target.value as any)}>
                            <option>RPP/Modul</option>
                            <option>Silabus/ATP</option>
                            <option>Media</option>
                            <option>Lainnya</option>
                        </select>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Tipe File</label>
                        <div className="btn-group w-100" role="group">
                            <input type="radio" className="btn-check" name="filetype" id="type1" checked={type === 'PDF'} onChange={() => setType('PDF')} />
                            <label className="btn btn-outline-success" htmlFor="type1">PDF</label>

                            <input type="radio" className="btn-check" name="filetype" id="type2" checked={type === 'DOC'} onChange={() => setType('DOC')} />
                            <label className="btn btn-outline-primary" htmlFor="type2">Word</label>

                            <input type="radio" className="btn-check" name="filetype" id="type3" checked={type === 'LINK'} onChange={() => setType('LINK')} />
                            <label className="btn btn-outline-secondary" htmlFor="type3">Link / Drive</label>
                        </div>
                    </div>

                    <div className="col-md-6">
                        <label className="form-label">File / Link</label>
                        {type === 'LINK' ? (
                            <input type="url" className="form-control" placeholder="https://..." value={linkInput} onChange={e => setLinkInput(e.target.value)} required />
                        ) : (
                            <input type="file" className="form-control" accept={type === 'PDF' ? '.pdf' : '.doc,.docx'} onChange={handleFileChange} required />
                        )}
                        {type !== 'LINK' && <div className="form-text text-danger small">* Maks 500KB (Gunakan Link jika file besar)</div>}
                    </div>

                    <div className="col-12 text-end">
                        <button type="submit" className="btn btn-primary px-4" disabled={loading}>
                            {loading ? 'Menyimpan...' : 'Simpan Dokumen'}
                        </button>
                    </div>
                </div>
            </form>
          </div>
        </div>
      )}

      {/* List Materials */}
      <div className="row g-3">
        {materials.length === 0 ? (
            <div className="text-center py-5 text-muted bg-white rounded border border-dashed">
                <span className="fs-1 d-block mb-2">📂</span>
                Belum ada perangkat ajar yang diupload.
            </div>
        ) : (
            materials.map(item => (
                <div key={item.id} className="col-md-6 col-lg-4">
                    <div className="card h-100 shadow-sm border-0 hover-shadow transition-all">
                        <div className="card-body">
                            <div className="d-flex align-items-start justify-content-between mb-2">
                                <span className="fs-1">{getIcon(item.type)}</span>
                                <div className="dropdown">
                                    <button className="btn btn-link text-muted p-0" onClick={() => handleDelete(item.id)}>🗑️</button>
                                </div>
                            </div>
                            <h6 className="fw-bold text-dark mb-1">{item.title}</h6>
                            <div className="mb-3">
                                <span className="badge bg-light text-secondary border me-1">{item.category}</span>
                                <small className="text-muted">{item.fileSize}</small>
                            </div>
                            <small className="text-muted d-block mb-3" style={{fontSize: '0.75rem'}}>
                                Diupload: {new Date(item.uploadDate).toLocaleDateString('id-ID')}
                            </small>

                            {item.type === 'LINK' ? (
                                <a href={item.fileData} target="_blank" rel="noopener noreferrer" className="btn btn-outline-secondary btn-sm w-100">
                                    🔗 Buka Link
                                </a>
                            ) : (
                                item.fileData ? (
                                    <a href={item.fileData} download={item.fileName} className={`btn btn-sm w-100 ${item.type === 'PDF' ? 'btn-outline-danger' : 'btn-outline-primary'}`}>
                                        ⬇️ Download File
                                    </a>
                                ) : (
                                    <button className="btn btn-light btn-sm w-100 disabled text-muted">File Corrupt</button>
                                )
                            )}
                        </div>
                    </div>
                </div>
            ))
        )}
      </div>
    </div>
  );
};

