  const grades = getGrades();
  const found = grades.find(g => g.studentId === studentId);
  if (found) return found;
  return {
    studentId,
    classId: '',
    formatif: Array(8).fill(0),
    sumatif: Array(5).fill(0),
    sasNonTes: 0,
