      // Limit file size for LocalStorage (e.g., 500KB limit to be safe)
      if (fileInput.size > 500 * 1024) {
        alert('Maaf, untuk penyimpanan lokal browser, ukuran file dibatasi maksimal 500KB. Gunakan opsi "Link Eksternal" (Google Drive) untuk file besar.');
        setLoading(false);
        return;
      }

      fileName = fileInput.name;
      fileSize = (fileInput.size / 1024).toFixed(1) + ' KB';

      // Convert to Base64
      fileData = await new Promise((resolve) => {
        const reader = new FileReader();
        reader.onloadend = () => resolve(reader.result as string);
        reader.readAsDataURL(fileInput);
      });
    }

    const newMaterial: TeachingMaterial = {
      id: Date.now().toString(),
      title,
      category,
      type,
      uploadDate: new Date().toISOString().split('T')[0],
      fileData,
      fileName,
      fileSize
    };

    saveMaterial(newMaterial);
    refreshData();
    resetForm();
    setLoading(false);
    setShowForm(false);
  };

  const resetForm = () => {
    setTitle('');
    setCategory('RPP/Modul');
    setType('PDF');
    setFileInput(null);
    setLinkInput('');
  };

  const handleDelete = (id: string) => {
    if(confirm('Hapus perangkat ajar ini?')) {
        deleteMaterial(id);
        refreshData();
    }
  };

  const getIcon = (type: string) => {
    switch(type) {
        case 'PDF': return '📕';
        case 'DOC': return '📘';
        case 'LINK': return '🔗';
        default: return '📄';
    }
  };

  const isPreviewable = (item: TeachingMaterial) => {
      // Allow preview for PDF
      if (item.type === 'PDF') return true;
      // Allow preview for DOC *IF* it is our simulated HTML format
      if (item.type === 'DOC' && item.fileData?.startsWith('data:text/html')) return true;
      // Allow preview for HTML data uris generally
      if (item.fileData && item.fileData.startsWith('data:text/html')) return true;

      return false;
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4">
        <div>
            <h2 className="text-dark fw-bold">Perangkat Pembelajaran</h2>
            <p className="text-muted mb-0">Arsip RPP, Modul Ajar, ATP, dan Media Pembelajaran.</p>
        </div>
        <button 
            className={`btn ${showForm ? 'btn-secondary' : 'btn-success'} shadow-sm`}
            onClick={() => setShowForm(!showForm)}
        >
            {showForm ? 'Batal' : '➕ Upload Perangkat'}
        </button>
      </div>

      {showForm && (
        <div className="card shadow border-0 mb-4 border-start border-4 border-success animate__animated animate__fadeIn">
          <div className="card-body">
            <h5 className="fw-bold mb-3">Upload Dokumen Baru</h5>
            <form onSubmit={handleSubmit}>
                <div className="row g-3">
                    <div className="col-md-6">
                        <label className="form-label">Judul Perangkat</label>
                        <input type="text" className="form-control" value={title} onChange={e => setTitle(e.target.value)} required placeholder="Contoh: Modul Ajar Bab 2" />
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Kategori</label>
                        <select className="form-select" value={category} onChange={e => setCategory(e.target.value as any)}>
                            <option>RPP/Modul</option>
                            <option>Silabus/ATP</option>
                            <option>Media</option>
                            <option>Lainnya</option>
                        </select>
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Tipe File</label>
                        <div className="btn-group w-100" role="group">
                            <input type="radio" className="btn-check" name="filetype" id="type1" checked={type === 'PDF'} onChange={() => setType('PDF')} />
                            <label className="btn btn-outline-danger" htmlFor="type1">PDF</label>

                            <input type="radio" className="btn-check" name="filetype" id="type2" checked={type === 'DOC'} onChange={() => setType('DOC')} />
                            <label className="btn btn-outline-primary" htmlFor="type2">Word</label>

                            <input type="radio" className="btn-check" name="filetype" id="type3" checked={type === 'LINK'} onChange={() => setType('LINK')} />
                            <label className="btn btn-outline-secondary" htmlFor="type3">Link / Drive</label>
                        </div>
                    </div>

                    <div className="col-md-6">
                        <label className="form-label">File / Link</label>
                        {type === 'LINK' ? (
                            <input type="url" className="form-control" placeholder="https://drive.google.com/..." value={linkInput} onChange={e => setLinkInput(e.target.value)} required />
                        ) : (
                            <input type="file" className="form-control" accept={type === 'PDF' ? '.pdf' : '.doc,.docx'} onChange={handleFileChange} required />
                        )}
                        {type !== 'LINK' && <div className="form-text text-danger small">* Maks 500KB (Gunakan Link untuk file besar)</div>}
                    </div>

                    <div className="col-12 text-end">
                        <button type="submit" className="btn btn-primary px-4" disabled={loading}>
                            {loading ? 'Menyimpan...' : 'Simpan Dokumen'}
                        </button>
                    </div>
                </div>
            </form>
          </div>
        </div>
      )}

      {/* DOCUMENT PREVIEW MODAL */}
      {previewMaterial && (
        <div className="modal d-block" style={{backgroundColor: 'rgba(0,0,0,0.6)', zIndex: 1050}} tabIndex={-1}>
          <div className="modal-dialog modal-xl modal-dialog-centered modal-dialog-scrollable" style={{height: '95vh'}}>
            <div className="modal-content h-100 shadow-lg">
              <div className="modal-header bg-light py-2">
                <div className="d-flex align-items-center">
                    <span className="me-2 fs-5">{getIcon(previewMaterial.type)}</span>
                    <h6 className="modal-title fw-bold text-truncate mb-0" style={{maxWidth: '80%'}}>
                        {previewMaterial.title}
                    </h6>
                </div>
                <button type="button" className="btn-close" onClick={() => setPreviewMaterial(null)}></button>
              </div>
              <div className="modal-body p-0 bg-dark d-flex align-items-center justify-content-center">
                 {/* Support for both PDF (base64) and HTML (data:text/html) previews via iframe */}
                 <iframe 
                      src={previewMaterial.fileData} 
                      width="100%" 
                      height="100%" 
                      style={{border: 'none', backgroundColor: '#fff'}}
                      title="Document Preview"
                 >
                   <p className="text-white text-center mt-5">Browser Anda tidak mendukung preview dokumen ini.</p>
                 </iframe>
              </div>
              <div className="modal-footer py-2 bg-light justify-content-between">
                 <span className="text-muted small">File: {previewMaterial.fileName}</span>
                 <div>
                    <a href={previewMaterial.fileData} download={previewMaterial.fileName} className="btn btn-success btn-sm me-2">
                        ⬇️ Download Asli
                    </a>
                    <button type="button" className="btn btn-secondary btn-sm" onClick={() => setPreviewMaterial(null)}>Tutup</button>
                 </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* List Materials */}
      <div className="row g-3">
        {materials.length === 0 ? (
            <div className="col-12">
                <div className="text-center py-5 text-muted bg-white rounded border border-dashed">
                    <span className="fs-1 d-block mb-2">📂</span>
                    <p className="mb-0">Belum ada perangkat ajar yang diupload.</p>
                </div>
            </div>
        ) : (
            materials.map(item => (
                <div key={item.id} className="col-md-6 col-lg-4">
                    <div className="card h-100 shadow-sm border-0 hover-shadow transition-all">
                        <div className="card-body d-flex flex-column">
                            <div className="d-flex align-items-start justify-content-between mb-2">
                                <span className="fs-1">{getIcon(item.type)}</span>
                                <div className="dropdown">
                                    <button 
                                        className="btn btn-light btn-sm rounded-circle text-danger" 
                                        onClick={() => handleDelete(item.id)}
                                        title="Hapus File"
                                    >
                                        🗑️
                                    </button>
                                </div>
                            </div>
                            <h6 className="fw-bold text-dark mb-1 text-truncate" title={item.title}>{item.title}</h6>
                            <div className="mb-3">
                                <span className="badge bg-light text-secondary border me-1">{item.category}</span>
                                <small className="text-muted" style={{fontSize: '0.75rem'}}>{item.fileSize}</small>
                            </div>

                            <div className="mt-auto">
                                <small className="text-muted d-block mb-2" style={{fontSize: '0.75rem'}}>
                                    📅 {new Date(item.uploadDate).toLocaleDateString('id-ID')}
                                </small>

                                {item.type === 'LINK' ? (
                                    <a href={item.fileData} target="_blank" rel="noopener noreferrer" className="btn btn-outline-primary btn-sm w-100 fw-bold">
                                        🔗 Buka Link
                                    </a>
                                ) : (
                                    <div className="d-flex gap-2">
                                        {/* Show Preview button if content allows it */}
                                        {isPreviewable(item) ? (
                                            <button 
                                                onClick={() => setPreviewMaterial(item)} 
                                                className="btn btn-outline-success btn-sm w-100 fw-bold"
                                            >
                                                👁️ Lihat File
                                            </button>
                                        ) : (
                                            /* Disable preview for non-previewable files (empty placeholders or corrupt) */
                                            (!item.fileData) && (
                                                <button disabled className="btn btn-light btn-sm w-100 text-muted">File Kosong</button>
                                            )
                                        )}

                                        {item.fileData && (
                                            <a 
                                                href={item.fileData} 
                                                download={item.fileName} 
                                                className={`btn btn-sm w-100 fw-bold ${isPreviewable(item) ? 'btn-outline-secondary' : 'btn-outline-primary'}`}
                                            >
                                                {isPreviewable(item) ? '⬇️ Unduh' : '⬇️ Download Word'}
                                            </a>
                                        )}
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>
                </div>
            ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { JournalEntry, Classroom } from '../types';
import { getClasses, getJournals, saveJournal, getUserProfile } from '../services/storageService';
import { SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const JournalManager: React.FC = () => {
  const [entries, setEntries] = useState<JournalEntry[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [showForm, setShowForm] = useState(false);

  // Status penyimpanan draft
  const [draftStatus, setDraftStatus] = useState<'idle' | 'saved'>('idle');

  const defaultForm = {
    date: new Date().toISOString().split('T')[0],
    attendanceSummary: { hadir: 0, izin: 0, sakit: 0, alfa: 0 }
  };

  const [form, setForm] = useState<Partial<JournalEntry>>(defaultForm);

  useEffect(() => {
    setClasses(getClasses());
    setEntries(getJournals().sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

    // LOAD DRAFT: Cek apakah ada tulisan yang belum disimpan sebelumnya
    const savedDraft = localStorage.getItem('ar_journal_draft');
    if (savedDraft) {
        try {
            const parsed = JSON.parse(savedDraft);
            setForm(parsed);
            // Jika ada draft, otomatis buka formnya
            if (Object.keys(parsed).length > 2) setShowForm(true); 
        } catch (e) {
            console.error("Gagal memuat draft jurnal", e);
        }
    }
  }, []);

  // AUTO-SAVE DRAFT: Setiap kali form berubah, simpan ke local storage sementara
  useEffect(() => {
      if (showForm) {
          localStorage.setItem('ar_journal_draft', JSON.stringify(form));
          setDraftStatus('saved');
          const timer = setTimeout(() => setDraftStatus('idle'), 1000);
          return () => clearTimeout(timer);
      }
  }, [form, showForm]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.topic || !form.classId) return;

    const entry: JournalEntry = {
      id: Date.now().toString(),
      date: form.date!,
      classId: form.classId!,
      topic: form.topic!,
      activity: form.activity || '',
      notes: form.notes || '',
      attendanceSummary: {
        hadir: Number(form.attendanceSummary?.hadir) || 0,
        izin: Number(form.attendanceSummary?.izin) || 0,
        sakit: Number(form.attendanceSummary?.sakit) || 0,
        alfa: Number(form.attendanceSummary?.alfa) || 0,
      }
    };

    saveJournal(entry);
    setEntries([entry, ...entries].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime()));

    // Reset Form & Hapus Draft
    setShowForm(false);
    setForm(defaultForm);
    localStorage.removeItem('ar_journal_draft');

    alert("Jurnal berhasil disimpan permanen.");
  };

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    const userProfile = getUserProfile();
    const fileName = `Jurnal_Mengajar_${new Date().toISOString().split('T')[0]}`;
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});

    let tableRows = '';
    entries.forEach((entry, idx) => {
        const className = classes.find(c => c.id === entry.classId)?.name || '-';
        const entryDate = new Date(entry.date).toLocaleDateString('id-ID');
        tableRows += `
            <tr>
                <td style="text-align:center; border:1px solid #000;">${idx + 1}</td>
                <td style="text-align:center; border:1px solid #000;">${entryDate}</td>
                <td style="text-align:center; border:1px solid #000;">${className}</td>
                <td style="border:1px solid #000;">${entry.topic}</td>
                <td style="border:1px solid #000;">${entry.activity}</td>
                <td style="text-align:center; font-size: 10pt; border:1px solid #000;">H:${entry.attendanceSummary.hadir}, I:${entry.attendanceSummary.izin}, S:${entry.attendanceSummary.sakit}, A:${entry.attendanceSummary.alfa}</td>
                <td style="border:1px solid #000;">${entry.notes}</td>
            </tr>
        `;
    });

    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="UTF-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 portrait; margin: 2cm; }
                body { font-family: 'Times New Roman', serif; font-size: 11pt; color: #000; }

                /* KOP SURAT STYLE */
                .kop-table { width: 100%; border-bottom: 3px double #000; margin-bottom: 20px; }
                .kop-table td { border: none; padding: 0; vertical-align: middle; }
                .kop-logo { width: 90px; text-align: center; }
                .kop-text { text-align: center; }
                .kop-text h4 { margin: 0; font-size: 14pt; font-weight: normal; margin-bottom: 2px; }
                .kop-text h3 { margin: 0; font-size: 14pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text p { margin: 0; font-size: 10pt; font-style: italic; }

                table.data-table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; font-size: 11pt; }
                table.data-table th { border: 1px solid #000; padding: 5px; vertical-align: top; background-color: #f2f2f2; font-weight: bold; text-align: center; }
                table.data-table td { border: 1px solid #000; padding: 5px; vertical-align: top; }

                .title-doc { text-align: center; font-weight: bold; text-decoration: underline; font-size: 12pt; margin-top: 10px; margin-bottom: 5px; }
                .sub-title { text-align: center; margin-bottom: 20px; }

                .signature-section { margin-top: 30px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <!-- KOP SURAT -->
            <table class="kop-table">
                <tr>
                    <td class="kop-logo">
                        <img src="${KEMENAG_LOGO_URL}" width="80" height="auto" alt="Logo">
                    </td>
                    <td class="kop-text">
                        <h4>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h4>
                        <h3>KANTOR KEMENTERIAN AGAMA KABUPATEN BULUKUMBA</h3>
                        <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                        <p>${KOP_ADDRESS}</p>
                    </td>
                </tr>
            </table>

            <div class="title-doc">JURNAL MENGAJAR GURU</div>
            <div class="sub-title">Mata Pelajaran: Bahasa Arab | Tahun Pelajaran 2024/2025</div>

            <table class="data-table">
                <thead>
                    <tr>
                        <th width="5%">No</th>
                        <th width="12%">Tanggal</th>
                        <th width="8%">Kelas</th>
                        <th width="20%">Materi / TP</th>
                        <th width="25%">Kegiatan Pembelajaran</th>
                        <th width="15%">Absensi</th>
                        <th width="15%">Catatan</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="50%">
                            Mengetahui,<br>
                            Kepala Madrasah,<br><br><br><br>
                            <b><u>( ........................... )</u></b><br>
                            NIP. ...........................
                        </td>
                        <td width="50%">
                            Bulukumba, ${dateStr}<br>
                            Guru Mata Pelajaran,<br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = type === 'excel' ? 'application/vnd.ms-excel' : 'application/msword';
    let extension = type === 'excel' ? 'xls' : 'doc';

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
        <h2 className="text-dark">Jurnal Mengajar Harian</h2>
        <div className="d-flex gap-2">
            <button onClick={() => setShowForm(!showForm)} className={`btn ${showForm ? 'btn-secondary' : 'btn-success'}`}>
                {showForm ? 'Batal' : '+ Tulis Jurnal'}
            </button>
            <div className="dropdown">
                <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                    📥 Backup Data
                </button>
                <ul className="dropdown-menu">
                    <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                    <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                    <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
                </ul>
            </div>
        </div>
      </div>

      {showForm && (
        <div className="card shadow mb-4 border-top border-success border-4 no-print animate__animated animate__fadeIn">
          <div className="card-body">
            <div className="d-flex justify-content-between align-items-center mb-3">
                <h5 className="text-center fw-bold mb-0">{SCHOOL_NAME} - Form Jurnal</h5>
                {draftStatus === 'saved' && <span className="badge bg-light text-success border">✅ Auto-Saved (Draft)</span>}
            </div>

            <form onSubmit={handleSubmit}>
                <div className="row g-3">
                    <div className="col-md-6">
                        <label className="form-label">Tanggal</label>
                        <input type="date" className="form-control" value={form.date} onChange={e => setForm({...form, date: e.target.value})} required />
                    </div>
                    <div className="col-md-6">
                        <label className="form-label">Kelas</label>
                        <select className="form-select" value={form.classId} onChange={e => setForm({...form, classId: e.target.value})} required>
                            <option value="">Pilih Kelas</option>
                            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                    <div className="col-12">
                        <label className="form-label">Materi / TP</label>
                        <input type="text" className="form-control" value={form.topic} onChange={e => setForm({...form, topic: e.target.value})} required />
                    </div>
                    <div className="col-12">
                        <label className="form-label">Kegiatan Pembelajaran</label>
                        <textarea className="form-control" rows={3} value={form.activity} onChange={e => setForm({...form, activity: e.target.value})} />
                    </div>
                    <div className="col-12">
                        <label className="form-label mb-1">Rekap Absensi (Jumlah Siswa)</label>
                        <div className="row g-2">
                            <div className="col">
                                <input type="number" placeholder="Hadir" className="form-control text-center border-success" value={form.attendanceSummary?.hadir} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, hadir: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Izin" className="form-control text-center border-info" value={form.attendanceSummary?.izin} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, izin: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Sakit" className="form-control text-center border-warning" value={form.attendanceSummary?.sakit} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, sakit: parseInt(e.target.value)}})} />
                            </div>
                            <div className="col">
                                <input type="number" placeholder="Alfa" className="form-control text-center border-danger" value={form.attendanceSummary?.alfa} onChange={e => setForm({...form, attendanceSummary: {...form.attendanceSummary!, alfa: parseInt(e.target.value)}})} />
                            </div>
                        </div>
                    </div>
                    <div className="col-12">
                        <label className="form-label">Catatan Khusus</label>
                        <textarea className="form-control" value={form.notes} onChange={e => setForm({...form, notes: e.target.value})} />
                    </div>
                    <div className="col-12">
                        <button type="submit" className="btn btn-success w-100">Simpan Jurnal Permanen</button>
                    </div>
                </div>
            </form>
          </div>
        </div>
      )}

      <div className="row g-3">
        {entries.length === 0 ? (
            <div className="text-center py-5 text-muted">
                Belum ada data jurnal. Silakan buat jurnal baru.
            </div>
        ) : (
            entries.map(entry => (
            <div key={entry.id} className="col-12">
                <div className="card shadow-sm h-100 hover-shadow break-inside-avoid">
                    <div className="card-body">
                        <div className="d-flex justify-content-between align-items-start border-bottom pb-2 mb-2">
                            <div>
                                <h5 className="fw-bold text-success mb-1">{entry.topic}</h5>
                                <small className="text-muted">
                                    {new Date(entry.date).toLocaleDateString('id-ID', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })} • 
                                    Kelas: {classes.find(c => c.id === entry.classId)?.name || '?'}
                                </small>
                            </div>
                        </div>
                        <p className="card-text text-dark mb-3" style={{whiteSpace: 'pre-line'}}>
                            <strong>Kegiatan:</strong> {entry.activity}
                        </p>
                        <div className="bg-light p-2 rounded d-flex gap-3 small mb-2">
                            <span className="fw-bold text-success">✅ H: {entry.attendanceSummary.hadir}</span>
                            <span className="fw-bold text-info">ℹ️ I: {entry.attendanceSummary.izin}</span>
                            <span className="fw-bold text-warning">🏥 S: {entry.attendanceSummary.sakit}</span>
                            <span className="fw-bold text-danger">❌ A: {entry.attendanceSummary.alfa}</span>
                        </div>
                        {entry.notes && (
                            <div className="alert alert-warning py-1 px-2 small mb-0 fst-italic">
                                Note: {entry.notes}
                            </div>
                        )}
                    </div>
                </div>
            </div>
            ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Student, Classroom, Gender } from '../types';
import { getStudents, saveStudent, deleteStudent, getClasses, getUserProfile } from '../services/storageService';
import { SCHOOL_NAME, KEMENAG_LOGO_URL, KOP_ADDRESS } from '../constants';

export const StudentManager: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [classes, setClasses] = useState<Classroom[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterClass, setFilterClass] = useState('');

  // Pagination state
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  const defaultForm = {
    nisn: '', name: '', gender: Gender.L, classId: ''
  };

  const [form, setForm] = useState<Partial<Student>>(defaultForm);
  const [editingId, setEditingId] = useState<string | null>(null);

  useEffect(() => {
    refresh();
    setClasses(getClasses());

    // Load Draft
    const savedDraft = localStorage.getItem('ar_student_form_draft');
    if (savedDraft) {
        try {
            setForm(JSON.parse(savedDraft));
        } catch(e){}
    }
  }, []);

  // Save Draft automatically
  useEffect(() => {
      if (!editingId) { // Only draft when creating new, not editing
         localStorage.setItem('ar_student_form_draft', JSON.stringify(form));
      }
  }, [form, editingId]);

  const refresh = () => setStudents(getStudents());

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!form.name || !form.classId) return;

    const student: Student = {
      id: editingId || Date.now().toString(),
      nisn: form.nisn || '',
      name: form.name,
      gender: form.gender || Gender.L,
      classId: form.classId
    };

    saveStudent(student);

    // Clear Draft
    setForm({ nisn: '', name: '', gender: Gender.L, classId: form.classId }); // Keep class selected for convenience
    localStorage.removeItem('ar_student_form_draft');

    setEditingId(null);
    refresh();
  };

  const handleEdit = (s: Student) => {
    setForm(s);
    setEditingId(s.id);
  };

  const handleDelete = (id: string, name: string) => {
    if (confirm(`Yakin ingin menghapus data siswa: ${name}?\n\nPERINGATAN: Data nilai dan absensi siswa ini juga akan terhapus permanen.`)) {
      deleteStudent(id);
      refresh();
    }
  };

  // Filter Logic
  const filteredStudents = students.filter(s => {
    const matchName = s.name.toLowerCase().includes(searchTerm.toLowerCase());
    const matchClass = filterClass ? s.classId === filterClass : true;
    return matchName && matchClass;
  });

  // Pagination Logic
  const totalPages = Math.ceil(filteredStudents.length / itemsPerPage);
  const currentData = filteredStudents.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  // --- Export Functions (PROFESSIONAL FORMAT) ---
  const handleExport = (type: 'excel' | 'word' | 'print') => {
    const userProfile = getUserProfile();
    const className = filterClass ? classes.find(c => c.id === filterClass)?.name : 'Semua Kelas';
    const fileName = `Data_Siswa_${className.replace(/\s+/g, '_')}`;
    const dateStr = new Date().toLocaleDateString('id-ID', {day: 'numeric', month: 'long', year: 'numeric'});

    // 1. Generate Rows
    let tableRows = '';
    filteredStudents.forEach((s, idx) => {
        tableRows += `
            <tr>
                <td style="text-align:center; vertical-align:middle; border: 1px solid black;">${idx + 1}</td>
                <td style="text-align:center; vertical-align:middle; border: 1px solid black; mso-number-format:'@';">${s.nisn || '-'}</td> 
                <td style="text-align:left; vertical-align:middle; padding-left:5px; border: 1px solid black;">${s.name}</td>
                <td style="text-align:center; vertical-align:middle; border: 1px solid black;">${s.gender}</td>
                <td style="text-align:center; vertical-align:middle; border: 1px solid black;">${classes.find(c => c.id === s.classId)?.name || '-'}</td>
            </tr>
        `;
    });

    // 2. Generate Full HTML Document with KOP
    const contentHTML = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="utf-8">
            <title>${fileName}</title>
            <style>
                @page { size: A4 portrait; margin: 2cm 2cm 2cm 2cm; }
                body { font-family: 'Times New Roman', serif; font-size: 12pt; color: #000; line-height: 1.15; }

                /* KOP SURAT STYLE */
                .kop-table { width: 100%; border-bottom: 3px double #000; margin-bottom: 20px; }
                .kop-table td { border: none; padding: 0; vertical-align: middle; }
                .kop-logo { width: 90px; text-align: center; }
                .kop-text { text-align: center; }
                .kop-text h4 { margin: 0; font-size: 14pt; font-weight: normal; margin-bottom: 2px; }
                .kop-text h3 { margin: 0; font-size: 14pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text h2 { margin: 0; font-size: 16pt; font-weight: bold; text-transform: uppercase; margin-bottom: 2px; }
                .kop-text p { margin: 0; font-size: 10pt; font-style: italic; }

                /* DATA TABLE */
                table.data-table { width: 100%; border-collapse: collapse; border-spacing: 0; margin-bottom: 20px; }
                table.data-table th { border: 1px solid #000; padding: 8px 4px; background-color: #f2f2f2; font-weight: bold; text-align: center; vertical-align: middle; }
                table.data-table td { border: 1px solid #000; padding: 5px 4px; font-size: 11pt; }

                .title-doc { text-align: center; font-weight: bold; text-decoration: underline; font-size: 14pt; margin-top: 15px; margin-bottom: 5px; }
                .sub-title { text-align: center; margin-bottom: 25px; font-size: 12pt; }

                .signature-section { margin-top: 40px; width: 100%; page-break-inside: avoid; }
                .signature-table { width: 100%; border: none; }
                .signature-table td { border: none; text-align: center; vertical-align: top; padding: 0; }
            </style>
        </head>
        <body>
            <!-- KOP SURAT -->
            <table class="kop-table">
                <tr>
                    <td class="kop-logo">
                        <img src="${KEMENAG_LOGO_URL}" width="80" height="auto" alt="Logo">
                    </td>
                    <td class="kop-text">
                        <h4>KEMENTERIAN AGAMA REPUBLIK INDONESIA</h4>
                        <h3>KANTOR KEMENTERIAN AGAMA KABUPATEN BULUKUMBA</h3>
                        <h2>${SCHOOL_NAME.toUpperCase()}</h2>
                        <p>${KOP_ADDRESS}</p>
                    </td>
                </tr>
            </table>

            <div class="title-doc">DATA SISWA TAHUN PELAJARAN 2024/2025</div>
            <div class="sub-title">Kelas: ${className}</div>

            <table class="data-table">
                <thead>
                    <tr>
                        <th width="5%">NO</th>
                        <th width="20%">NISN</th>
                        <th width="45%">NAMA LENGKAP</th>
                        <th width="10%">L/P</th>
                        <th width="20%">KELAS</th>
                    </tr>
                </thead>
                <tbody>${tableRows}</tbody>
            </table>

            <div class="signature-section">
                <table class="signature-table">
                    <tr>
                        <td width="65%"></td>
                        <td width="35%">
                            Bulukumba, ${dateStr}<br>
                            Wali Kelas / Guru,<br>
                            <br><br><br><br>
                            <strong><u>${userProfile.name}</u></strong><br>
                            NIP. ${userProfile.nip || '-'}
                        </td>
                    </tr>
                </table>
            </div>
        </body>
        </html>
    `;

    if (type === 'print') {
        const iframe = document.createElement('iframe');
        iframe.style.display = 'none';
        document.body.appendChild(iframe);
        const doc = iframe.contentWindow?.document;
        if (doc) {
            doc.open();
            doc.write(contentHTML);
            doc.close();
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();
        }
        setTimeout(() => document.body.removeChild(iframe), 1000);
        return;
    }

    let mimeType = '';
    let extension = '';

    if (type === 'excel') {
        mimeType = 'application/vnd.ms-excel';
        extension = 'xls';
    } else if (type === 'word') {
        mimeType = 'application/msword';
        extension = 'doc';
    }

    const blob = new Blob([contentHTML], { type: mimeType });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${fileName}.${extension}`;
    a.click();
  };

  return (
    <div>
      <div className="d-flex justify-content-between align-items-center mb-4 no-print">
         <h2 className="text-dark">Data Siswa</h2>
         <div className="dropdown">
            <button className="btn btn-primary dropdown-toggle" type="button" data-bs-toggle="dropdown">
                📥 Backup Data
            </button>
            <ul className="dropdown-menu">
                <li><button className="dropdown-item" onClick={() => handleExport('excel')}>📊 Export Excel (Rapi)</button></li>
                <li><button className="dropdown-item" onClick={() => handleExport('word')}>📄 Export Word (Rapi)</button></li>
                <li><button className="dropdown-item" onClick={() => handleExport('print')}>🖨️ Print / PDF</button></li>
            </ul>
        </div>
      </div>

      <div className="row g-4">
        {/* Form Input */}
        <div className="col-lg-4 no-print">
          <div className="card shadow-sm border-0">
             <div className="card-header bg-success text-white fw-bold d-flex justify-content-between">
              <span>{editingId ? 'Edit Siswa' : 'Tambah Siswa'}</span>
              {!editingId && form.name && <span className="badge bg-light text-dark small">Draft Saved</span>}
            </div>
            <div className="card-body">
              <form onSubmit={handleSubmit}>
                 <div className="mb-3">
                  <label className="form-label">NISN</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.nisn}
                    onChange={e => setForm({...form, nisn: e.target.value})}
                  />
                </div>
                <div className="mb-3">
                  <label className="form-label">Nama Lengkap</label>
                  <input
                    type="text"
                    className="form-control"
                    value={form.name}
                    onChange={e => setForm({...form, name: e.target.value})}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label className="form-label">Jenis Kelamin</label>
                  <select
                    className="form-select"
                    value={form.gender}
                    onChange={e => setForm({...form, gender: e.target.value as Gender})}
                  >
                    <option value={Gender.L}>Laki-laki</option>
                    <option value={Gender.P}>Perempuan</option>
                  </select>
                </div>
                <div className="mb-3">
                  <label className="form-label">Kelas</label>
                  <select
                    className="form-select"
                    value={form.classId}
                    onChange={e => setForm({...form, classId: e.target.value})}
                    required
                  >
                    <option value="">Pilih Kelas...</option>
                    {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                  </select>
                </div>
                <div className="d-flex gap-2">
                    <button type="submit" className="btn btn-success flex-grow-1">
                      {editingId ? 'Update' : 'Simpan'}
                    </button>
                     {editingId && (
                        <button 
                            type="button" 
                            onClick={() => { setEditingId(null); setForm(defaultForm); localStorage.removeItem('ar_student_form_draft'); }}
                            className="btn btn-secondary"
                        >
                            Batal
                        </button>
                    )}
                </div>
              </form>
            </div>
          </div>
        </div>

        {/* List & Search */}
        <div className="col-lg-8">
          <div className="card shadow-sm border-0">
             <div className="card-header bg-white p-3 no-print">
                <div className="row g-2">
                    <div className="col-md-7">
                        <input
                            type="text"
                            placeholder="🔍 Cari nama siswa..."
                            className="form-control"
                            value={searchTerm}
                            onChange={e => setSearchTerm(e.target.value)}
                        />
                    </div>
                    <div className="col-md-5">
                        <select
                            className="form-select"
                            value={filterClass}
                            onChange={e => setFilterClass(e.target.value)}
                        >
                            <option value="">Semua Kelas</option>
                            {classes.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                        </select>
                    </div>
                </div>
             </div>

             <div className="table-responsive">
                <table id="student-table" className="table table-hover table-striped mb-0 align-middle">
                    <thead className="table-light">
                        <tr>
                        <th className="ps-3">NISN</th>
                        <th>Nama</th>
                        <th>L/P</th>
                        <th>Kelas</th>
                        <th className="text-end pe-3 no-print">Aksi</th>
                        </tr>
                    </thead>
                    <tbody>
                        {currentData.length > 0 ? currentData.map(s => (
                        <tr key={s.id}>
                            <td className="ps-3 small text-muted">{s.nisn}</td>
                            <td className="fw-bold">{s.name}</td>
                            <td>{s.gender}</td>
                            <td>
                                <span className="badge bg-light text-dark border">
                                    {classes.find(c => c.id === s.classId)?.name || '-'}
                                </span>
                            </td>
                            <td className="text-end pe-3 no-print">
                                <button onClick={() => handleEdit(s)} className="btn btn-sm btn-link text-decoration-none">Edit</button>
                                <button onClick={() => handleDelete(s.id, s.name)} className="btn btn-sm btn-link text-danger text-decoration-none">Hapus</button>
                            </td>
                        </tr>
                        )) : (
                            <tr><td colSpan={5} className="text-center py-4 text-muted">Tidak ada data siswa ditemukan</td></tr>
                        )}
                    </tbody>
                </table>
             </div>

             {/* Pagination */}
             {totalPages > 1 && (
                 <div className="card-footer bg-white d-flex justify-content-end no-print">
                    <nav>
                        <ul className="pagination pagination-sm mb-0">
                            <li className={`page-item ${currentPage === 1 ? 'disabled' : ''}`}>
                                <button className="page-link" onClick={() => setCurrentPage(c => Math.max(c - 1, 1))}>Previous</button>
                            </li>
                            {Array.from({length: totalPages}, (_, i) => (
                                <li key={i} className={`page-item ${currentPage === i + 1 ? 'active' : ''}`}>
                                    <button className="page-link" onClick={() => setCurrentPage(i + 1)}>{i + 1}</button>
                                </li>
                            ))}
                            <li className={`page-item ${currentPage === totalPages ? 'disabled' : ''}`}>
                                <button className="page-link" onClick={() => setCurrentPage(c => Math.min(c + 1, totalPages))}>Next</button>
                            </li>
                        </ul>
                    </nav>
                 </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { UserProfile } from '../types';
import { saveUserProfile } from '../services/storageService';

interface ProfileManagerProps {
  userProfile: UserProfile;
  onProfileUpdate: (updated: UserProfile) => void;
}

export const ProfileManager: React.FC<ProfileManagerProps> = ({ userProfile, onProfileUpdate }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState<UserProfile>(userProfile);
  const [saveStatus, setSaveStatus] = useState<'idle' | 'saving' | 'saved'>('idle');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const restoreInputRef = useRef<HTMLInputElement>(null);

  // Auto-Save Effect with Debounce
  useEffect(() => {
    if (isEditing) {
        // Jangan simpan jika data sama persis
        if (JSON.stringify(formData) === JSON.stringify(userProfile)) return;

        setSaveStatus('saving');
        const handler = setTimeout(() => {
            saveUserProfile(formData);
            onProfileUpdate(formData);
            setSaveStatus('saved');
            setTimeout(() => setSaveStatus('idle'), 2000);
        }, 800); // Wait 800ms after typing stops

        return () => clearTimeout(handler);
    }
  }, [formData, isEditing]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  // Fungsi untuk Memproses Foto (Resize & Compress) agar muat di LocalStorage
  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      try {
        if (!file.type.startsWith('image/')) {
            alert('Mohon upload file gambar yang valid.');
            return;
        }

        const resizeAndCompressImage = (imageFile: File): Promise<string> => {
            return new Promise((resolve) => {
                const reader = new FileReader();
                reader.onload = (readerEvent) => {
                    const img = new Image();
                    img.onload = () => {
                        const canvas = document.createElement('canvas');
                        const MAX_SIZE = 400; // Maksimal ukuran sisi 400px (Cukup untuk avatar)
                        let width = img.width;
                        let height = img.height;

                        if (width > height) {
                            if (width > MAX_SIZE) {
                                height *= MAX_SIZE / width;
                                width = MAX_SIZE;
                            }
                        } else {
                            if (height > MAX_SIZE) {
                                width *= MAX_SIZE / height;
                                height = MAX_SIZE;
                            }
                        }

                        canvas.width = width;
                        canvas.height = height;
                        const ctx = canvas.getContext('2d');
                        if (ctx) {
                            ctx.drawImage(img, 0, 0, width, height);
                            const dataUrl = canvas.toDataURL('image/jpeg', 0.7);
                            resolve(dataUrl);
                        } else {
                            resolve(readerEvent.target?.result as string);
                        }
                    };
                    img.src = readerEvent.target?.result as string;
                };
                reader.readAsDataURL(imageFile);
            });
        };

        const compressedPhoto = await resizeAndCompressImage(file);

        // Immediate save for photo
        const updatedProfile = { ...formData, photo: compressedPhoto };
        setFormData(updatedProfile);
        saveUserProfile(updatedProfile);
        onProfileUpdate(updatedProfile);

      } catch (error) {
          console.error("Gagal memproses gambar:", error);
          alert("Terjadi kesalahan saat memproses gambar.");
      }
    }
  };

  const triggerFileInput = () => {
      if (fileInputRef.current) {
          fileInputRef.current.value = ''; 
          fileInputRef.current.click();
      }
  };

  // --- BACKUP & RESTORE LOGIC ---
  const handleDownloadBackup = () => {
    const keys = ['ar_classes', 'ar_students', 'ar_grades', 'ar_attendance', 'ar_journal', 'ar_user_profile'];
    const backup: Record<string, any> = {};

    keys.forEach(k => {
        const raw = localStorage.getItem(k);
        if (raw) backup[k] = JSON.parse(raw);
    });

    const json = JSON.stringify(backup, null, 2);
    const blob = new Blob([json], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `BACKUP_NILAI_MTSN2_${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const handleRestoreBackup = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
        try {
            const json = event.target?.result as string;
            const data = JSON.parse(json);

            if (!data.ar_classes && !data.ar_students) {
                alert('File tidak valid! Pastikan file adalah hasil backup dari aplikasi ini.');
                return;
            }

            if (confirm('PERINGATAN: Fitur ini akan MENIMPA (MENGHAPUS) semua data yang ada saat ini dengan data dari file backup.\n\nApakah Anda yakin ingin melanjutkan?')) {
                Object.keys(data).forEach(key => {
                    localStorage.setItem(key, JSON.stringify(data[key]));
                });
                alert('Data berhasil dipulihkan! Aplikasi akan dimuat ulang.');
                window.location.reload();
            }
        } catch (err) {
            console.error(err);
            alert('Gagal membaca file backup. Pastikan format file benar (JSON).');
        }
    };
    reader.readAsText(file);
    if (restoreInputRef.current) restoreInputRef.current.value = ''; 
  };

  return (
    <div className="container-fluid">
      <h2 className="mb-4 text-dark font-arabic">Profil Pengguna</h2>

      <div className="row g-4 justify-content-center">
        <div className="col-lg-8">
          <div className="card shadow-lg border-0 overflow-hidden">
            <div className="card-header bg-success text-white p-4 text-center position-relative" style={{backgroundImage: 'linear-gradient(45deg, #0f5132, #198754)'}}>
               {/* Decorative Circle Background */}
               <div style={{
                   position: 'absolute', top: '-50%', left: '50%', transform: 'translateX(-50%)', 
                   width: '400px', height: '400px', background: 'rgba(255,255,255,0.1)', 
                   borderRadius: '50%', zIndex: 0
               }}></div>

               <div className="position-relative" style={{zIndex: 1}}>
                   <div className="mb-3 d-inline-block p-1 bg-white rounded-circle shadow position-relative">
                        {formData.photo ? (
                            <img 
                                src={formData.photo} 
                                alt="Profile" 
                                className="rounded-circle object-fit-cover" 
                                style={{width: '120px', height: '120px'}}
                            />
                        ) : (
                            <div className="rounded-circle bg-light d-flex align-items-center justify-content-center text-secondary" style={{width: '120px', height: '120px', fontSize: '3rem'}}>
                                👤
                            </div>
                        )}

                        {isEditing && (
                            <button 
                                type="button"
                                onClick={triggerFileInput}
                                className="btn btn-sm btn-warning position-absolute bottom-0 end-0 rounded-circle border border-white shadow-sm"
                                style={{width: '35px', height: '35px', padding: 0}}
                                title="Ganti Foto"
                            >
                                📷
                            </button>
                        )}
                   </div>
                   <h3 className="font-arabic mb-0">{formData.name}</h3>
                   <p className="opacity-75 mb-0">{formData.role}</p>
               </div>
            </div>

            <div className="card-body p-4">
              {!isEditing ? (
                <>
                <div className="row g-4">
                  <div className="col-md-6">
                    <label className="text-muted small text-uppercase fw-bold mb-1">Nama Lengkap</label>
                    <div className="fs-5 fw-bold text-dark border-bottom pb-2">{userProfile.name}</div>
                  </div>
                  <div className="col-md-6">
                     <label className="text-muted small text-uppercase fw-bold mb-1">NIP</label>
                     <div className="fs-5 fw-bold text-dark border-bottom pb-2">{userProfile.nip || '-'}</div>
                  </div>
                  <div className="col-md-6">
                     <label className="text-muted small text-uppercase fw-bold mb-1">Jabatan</label>
                     <div className="fs-5 fw-bold text-dark border-bottom pb-2">{userProfile.role}</div>
